#include <memory>
#include <string>
#include <new>
#include <cstddef>
#include <print>

int main() {
    // Replacement for std::aligned_storage — use alignas + std::byte:
    alignas(int) std::byte storage[sizeof(int)];
    new (storage) int{42};
    int* p = std::launder(reinterpret_cast<int*>(storage));
    std::println("value from aligned storage: {}", *p);
    // int is trivially destructible — no explicit destructor call needed

    // Replacement for reserve() without args:
    std::string s = "Hello, this is a string that was previously longer";
    s = "short";
    s.shrink_to_fit(); // not s.reserve() — the deprecated form
    std::println("after shrink_to_fit, size: {}, capacity >= size: {}",
        s.size(), s.capacity() >= s.size());

    // Consistent string literals — only same-kind concatenation:
    const char* combined = "hello" " " "world"; // OK — all narrow
    std::println("combined: {}", combined);
}

#include <cstdint>
#include <print>

// Scoped enum with explicit underlying type — no narrowing ambiguity:
enum class Register : uint8_t {
    STATUS  = 0x00,
    CONTROL = 0x01,
    DATA    = 0x02
};

// Correct use of volatile: hardware register simulation
volatile uint8_t hw_register = 0;

void write_register(Register reg, uint8_t value) {
    // In real code, this would write to a memory-mapped hardware register
    hw_register = value;
    std::println("wrote {:02x} to register {:02x}",
        value, static_cast<uint8_t>(reg));
}

int main() {
    // Enum initialization — only valid enumerator values:
    Register r = Register::CONTROL;
    std::println("register value: {}", static_cast<int>(r));

    write_register(Register::DATA, 0xFF);
    // volatile cannot be passed directly to std::format — cast required:
    std::println("hw_register: {}", static_cast<uint8_t>(hw_register));

    // String concatenation — consistently narrow:
    const char* greeting = "C++" "23"; // OK
    std::println("standard: {}", greeting);
}
